(async function(params) {
  const width = params.width || 1920;
  const height = params.height || 1080;
  const samplesPerPixel = params.param || 16;

  const startTime = performance.now();

  class Vec3 {
    constructor(x, y, z) {
      this.x = x;
      this.y = y;
      this.z = z;
    }

    add(v) {
      return new Vec3(this.x + v.x, this.y + v.y, this.z + v.z);
    }

    sub(v) {
      return new Vec3(this.x - v.x, this.y - v.y, this.z - v.z);
    }

    mul(t) {
      return new Vec3(this.x * t, this.y * t, this.z * t);
    }

    dot(v) {
      return this.x * v.x + this.y * v.y + this.z * v.z;
    }

    length() {
      return Math.sqrt(this.x * this.x + this.y * this.y + this.z * this.z);
    }

    normalize() {
      const len = this.length();
      return new Vec3(this.x / len, this.y / len, this.z / len);
    }
  }

  class Ray {
    constructor(origin, direction) {
      this.origin = origin;
      this.direction = direction;
    }

    at(t) {
      return this.origin.add(this.direction.mul(t));
    }
  }

  class Sphere {
    constructor(center, radius, color) {
      this.center = center;
      this.radius = radius;
      this.color = color;
    }

    hit(ray, tMin, tMax) {
      const oc = ray.origin.sub(this.center);
      const a = ray.direction.dot(ray.direction);
      const halfB = oc.dot(ray.direction);
      const c = oc.dot(oc) - this.radius * this.radius;
      const discriminant = halfB * halfB - a * c;

      if (discriminant < 0) return null;

      const sqrtd = Math.sqrt(discriminant);
      let root = (-halfB - sqrtd) / a;

      if (root < tMin || tMax < root) {
        root = (-halfB + sqrtd) / a;
        if (root < tMin || tMax < root) return null;
      }

      const point = ray.at(root);
      const normal = point.sub(this.center).mul(1 / this.radius);

      return {
        t: root,
        point: point,
        normal: normal,
        color: this.color
      };
    }
  }

  const scene = [
    new Sphere(new Vec3(0, 0, -1), 0.5, new Vec3(0.8, 0.3, 0.3)),
    new Sphere(new Vec3(-1, 0, -1), 0.5, new Vec3(0.3, 0.8, 0.3)),
    new Sphere(new Vec3(1, 0, -1), 0.5, new Vec3(0.3, 0.3, 0.8)),
    new Sphere(new Vec3(0, -100.5, -1), 100, new Vec3(0.5, 0.5, 0.5))
  ];

  function rayColor(ray, depth) {
    if (depth <= 0) return new Vec3(0, 0, 0);

    let closestHit = null;
    let closestT = Infinity;

    for (const sphere of scene) {
      const hit = sphere.hit(ray, 0.001, closestT);
      if (hit && hit.t < closestT) {
        closestT = hit.t;
        closestHit = hit;
      }
    }

    if (closestHit) {
      const target = closestHit.point.add(closestHit.normal).add(
        new Vec3(
          (Math.random() - 0.5) * 0.5,
          (Math.random() - 0.5) * 0.5,
          (Math.random() - 0.5) * 0.5
        )
      );

      const newRay = new Ray(closestHit.point, target.sub(closestHit.point).normalize());
      const bounceColor = rayColor(newRay, depth - 1);

      return new Vec3(
        closestHit.color.x * bounceColor.x,
        closestHit.color.y * bounceColor.y,
        closestHit.color.z * bounceColor.z
      );
    }

    const unitDirection = ray.direction.normalize();
    const t = 0.5 * (unitDirection.y + 1.0);
    const white = new Vec3(1, 1, 1);
    const skyBlue = new Vec3(0.5, 0.7, 1.0);

    return white.mul(1 - t).add(skyBlue.mul(t));
  }

  const aspectRatio = width / height;
  const viewportHeight = 2.0;
  const viewportWidth = aspectRatio * viewportHeight;
  const focalLength = 1.0;

  const origin = new Vec3(0, 0, 0);
  const horizontal = new Vec3(viewportWidth, 0, 0);
  const vertical = new Vec3(0, viewportHeight, 0);
  const lowerLeftCorner = origin.sub(horizontal.mul(0.5)).sub(vertical.mul(0.5)).sub(new Vec3(0, 0, focalLength));

  const pixels = new Uint8ClampedArray(width * height * 4);
  let totalRays = 0;
  let totalBounces = 0;

  for (let j = 0; j < height; j++) {
    for (let i = 0; i < width; i++) {
      let pixelColor = new Vec3(0, 0, 0);

      for (let s = 0; s < samplesPerPixel; s++) {
        const u = (i + Math.random()) / (width - 1);
        const v = (j + Math.random()) / (height - 1);

        const direction = lowerLeftCorner
          .add(horizontal.mul(u))
          .add(vertical.mul(v))
          .sub(origin);

        const ray = new Ray(origin, direction);
        const color = rayColor(ray, 3);

        pixelColor = pixelColor.add(color);
        totalRays++;
        totalBounces += 3;
      }

      const scale = 1.0 / samplesPerPixel;
      const r = Math.sqrt(pixelColor.x * scale);
      const g = Math.sqrt(pixelColor.y * scale);
      const b = Math.sqrt(pixelColor.z * scale);

      const index = (j * width + i) * 4;
      pixels[index] = Math.floor(256 * Math.min(r, 0.999));
      pixels[index + 1] = Math.floor(256 * Math.min(g, 0.999));
      pixels[index + 2] = Math.floor(256 * Math.min(b, 0.999));
      pixels[index + 3] = 255;
    }

    if (j % 50 === 0 && j > 0) {
      await new Promise(resolve => setTimeout(resolve, 0));
    }
  }

  const took_ms = performance.now() - startTime;
  const mpxPerSec = (width * height) / (took_ms / 1000) / 1000000;
  const raysPerSec = totalRays / (took_ms / 1000);

  return {
    resolution: width + 'x' + height,
    pixels: width * height,
    samplesPerPixel,
    totalRays,
    totalBounces,
    avgBouncesPerRay: (totalBounces / totalRays).toFixed(2),
    spheresInScene: scene.length,
    took_ms: Math.round(took_ms),
    throughput: (width * height) / (took_ms / 1000),
    mpxPerSec: mpxPerSec.toFixed(3) + ' Mpx/s',
    raysPerSecond: Math.round(raysPerSec).toLocaleString(),
    estimatedMemory: ((width * height * 4) / 1024 / 1024).toFixed(2) + ' MB'
  };
})
